import React from "react";
import OrderItem from "./OrderItem";

export default function OrdersList({ orders, onEdit, onDelete }) {
    if (!orders.length) return <div className="empty">Заказов пока нет</div>;
    return (
        <div className="list">
            {orders.map(o => <OrderItem key={o.id} order={o} onEdit={onEdit} onDelete={onDelete} />)}
        </div>
    );
}
